import React, { useEffect, useState } from 'react';
import SellerBadge from '../components/SellerBadge';
import { Link } from 'react-router-dom';
import axios from 'axios';

const Dashboard = () => {
  const [user, setUser] = useState({ email: '', isVerified: false });
  const [history, setHistory] = useState([]);
  const [myListings, setMyListings] = useState([]);

  useEffect(() => {
    const email = localStorage.getItem('userEmail');
    const isVerified = localStorage.getItem('isVerified') === 'true';
    const userId = localStorage.getItem('userId');
    
    setUser({ email, isVerified });

    const fetchData = async () => {
      try {
        const historyRes = await axios.get(`http://localhost:5000/api/transactions/history/${userId}`);
        setHistory(historyRes.data);

        const listingsRes = await axios.get(`http://localhost:5000/api/items/user-listings/${userId}`);
        setMyListings(listingsRes.data);
      } catch (err) {
        console.error("Error fetching dashboard data", err);
      }
    };

    if (userId) fetchData();
  }, []);

  return (
    <div style={pageWrapper}>
      <header style={headerStyle}>
        <h1 style={welcomeText}>
          <span style={{ marginRight: '8px' }}>Welcome,</span>
          <span style={{ fontWeight: '600' }}>{user.email}</span>
          <div style={{ display: 'inline-block', marginLeft: '10px', verticalAlign: 'middle' }}>
            <SellerBadge isVerified={user.isVerified} />
          </div>
        </h1>
      </header>

      <section style={activitySection}>
        <h3 style={sectionTitle}>Your Activity</h3>
        
        <div style={gridContainer}>
          {/* Column 1: Active Listings */}
          <div style={cardStyle}>
            <div style={cardHeader}>
              <h4 style={cardTitle}>Your Active Listings</h4>
              <Link to="/create-listing" style={{ textDecoration: 'none' }}>
                <button style={addButton}>+ New Listing</button>
              </Link>
            </div>
            
            <div style={listContainer}>
              {myListings.length > 0 ? (
                myListings.map((item) => (
                  <div key={item._id} style={listItem}>
                    <div>
                      <div style={itemTitle}>{item.title}</div>
                      <div style={itemSubtext}>{item.category}</div>
                    </div>
                    <div style={itemPrice}>${item.price}</div>
                  </div>
                ))
              ) : (
                <p style={emptyText}>You haven't listed any items yet.</p>
              )}
            </div>
          </div>

          {/* Column 2: Order History */}
          <div style={cardStyle}>
            <div style={cardHeader}>
              <h4 style={cardTitle}>Order History</h4>
            </div>
            
            <div style={listContainer}>
              {history.length > 0 ? (
                history.map((tx) => (
                  <div key={tx._id} style={listItem}>
                    <div>
                      <div style={itemTitle}>{tx.title}</div>
                      <div style={itemSubtext}>Purchased on {new Date(tx.purchaseDate).toLocaleDateString()}</div>
                    </div>
                    <div style={itemPrice}>${tx.price}</div>
                  </div>
                ))
              ) : (
                <p style={emptyText}>No recent transactions found.</p>
              )}
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

// --- Styles ---

const pageWrapper = {
  padding: '60px 80px',
  backgroundColor: '#fdfcf0', // Consistent pastel cream
  minHeight: '100vh',
  fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif",
  color: '#202124'
};

const headerStyle = {
  marginBottom: '40px'
};

const welcomeText = {
  fontSize: '28px',
  fontWeight: '300',
  margin: 0,
  display: 'flex',
  alignItems: 'center'
};

const activitySection = {
  marginTop: '20px'
};

const sectionTitle = {
  fontSize: '18px',
  fontWeight: '600',
  marginBottom: '24px',
  color: '#5f6368',
  textTransform: 'uppercase',
  letterSpacing: '0.5px'
};

const gridContainer = {
  display: 'grid',
  gridTemplateColumns: '1fr 1fr',
  gap: '30px'
};

const cardStyle = {
  backgroundColor: '#ffffff',
  borderRadius: '12px',
  border: '1px solid #dadce0',
  padding: '24px',
  boxShadow: '0 1px 2px 0 rgba(60,64,67,.3), 0 1px 3px 1px rgba(60,64,67,.15)',
  display: 'flex',
  flexDirection: 'column'
};

const cardHeader = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '20px',
  borderBottom: '1px solid #f1f3f4',
  paddingBottom: '15px'
};

const cardTitle = {
  fontSize: '18px',
  fontWeight: '500',
  margin: 0
};

const addButton = {
  backgroundColor: '#1a73e8', // Matching Google Blue
  color: 'white',
  border: 'none',
  padding: '8px 16px',
  borderRadius: '20px', // Pill shape for modern look
  fontSize: '13px',
  fontWeight: '600',
  cursor: 'pointer',
  transition: 'background-color 0.2s'
};

const listContainer = {
  display: 'flex',
  flexDirection: 'column',
  gap: '12px'
};

const listItem = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '12px 0',
  borderBottom: '1px solid #f8f9fa'
};

const itemTitle = {
  fontSize: '15px',
  fontWeight: '600',
  color: '#202124'
};

const itemSubtext = {
  fontSize: '13px',
  color: '#70757a'
};

const itemPrice = {
  fontWeight: '600',
  fontSize: '15px',
  color: '#1e8e3e' // Subtle green for money
};

const emptyText = {
  color: '#70757a',
  fontSize: '14px',
  fontStyle: 'italic'
};

export default Dashboard;
